import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [hovered, setHovered] = useState(false);
  const [clicked, setClicked] = useState(false);

  const handleClick = () => {
    setClicked(true);
    setTimeout(() => setClicked(false), 3000);
  };

  return (
    <motion.section
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={handleClick}
      animate={{
        scale: clicked ? 1.05 : 1,
        backgroundColor: hovered ? "#154734" : "transparent",
        color: hovered ? "#ddcba4" : "black"
      }}
      transition={{
        duration: clicked ? 3 : 0.3,
        type: "spring",
      }}
      style={{
        cursor: "pointer",
        borderRadius: "1rem",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        color: hovered ? "#ddcba4" : "black", // seguridad redundante
        ...style,
      }}
    >
      {/* Forzamos herencia de color */}
      <div style={{ width: "100%", color: hovered ? "#ddcba4" : "black" }}>
        {children}
      </div>
    </motion.section>
  );
};

export default AnimatedSection;
